import java.io.*;
import java.util.*;

public class Main {
    static int[] left, right, isChild;

    static int dfs(int node) {
        if (node == 0) return 0;
        int lh = dfs(left[node]);
        if (lh == -1) return -1;
        int rh = dfs(right[node]);
        if (rh == -1) return -1;
        if (Math.abs(lh - rh) > 1) return -1;
        return 1 + Math.max(lh, rh);
    }

    // Reads the next non‑empty line (ignores blank lines and lines with only whitespace)
    private static String nextNonEmpty(BufferedReader br) throws IOException {
        String line;
        while ((line = br.readLine()) != null) {
            line = line.trim();
            if (!line.isEmpty()) return line;
        }
        return null; // end of stream
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        String line = nextNonEmpty(br);
        if (line == null) return; // no input
        int T = Integer.parseInt(line);
        while (T-- > 0) {
            line = nextNonEmpty(br);
            if (line == null) break; // safety
            int N = Integer.parseInt(line);
            left = new int[N + 1];
            right = new int[N + 1];
            isChild = new int[N + 1];
            for (int i = 0; i < N - 1; i++) {
                line = nextNonEmpty(br);
                // In well‑formed input this will never be null, but guard anyway
                if (line == null) break;
                StringTokenizer st = new StringTokenizer(line);
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                if (dir == 'L') left[p] = c; else right[p] = c;
                isChild[c] = 1;
            }
            int root = 1;
            for (int i = 1; i <= N; i++) {
                if (isChild[i] == 0) { root = i; break; }
            }
            int res = dfs(root);
            out.append(res == -1 ? "NO" : "YES").append('\n');
        }
        System.out.print(out.toString());
    }
}

